('C1', 3078, $$Formação de palavras: sufixos$$, $$-tion, -ness, -ful, -ly$$, $$🧱$$,
$$Sufixos mudam a classe da palavra: -tion/-ment (substantivo: information), -ness (happiness), -ful/-less (careful/careless), -ly (advérbio: quickly), -able (comfortable).$$,
$$Reconhecer sufixos ajuda a deduzir o significado e a classe.$$,
$j$[{"en": "Happiness comes from within.", "pt": "A felicidade vem de dentro."}, {"en": "Please be careful.", "pt": "Por favor, tenha cuidado."}, {"en": "She spoke quickly.", "pt": "Ela falou rápido."}]$j$::jsonb,
$j$[{"q": "'happy' + ness =", "ctx": "", "opts": ["happiness (subst.)", "happyness", "happness", "happily"], "ans": 0, "exp": "happiness."}, {"q": "Sufixo que forma advérbio:", "ctx": "", "opts": ["-ly", "-tion", "-ness", "-ful"], "ans": 0, "exp": "-ly (quickly)."}, {"q": "'care' + ful =", "ctx": "", "opts": ["careful (com cuidado)", "careless", "carely", "caretion"], "ans": 0, "exp": "careful."}, {"q": "'-less' significa:", "ctx": "", "opts": ["sem (careless = sem cuidado)", "cheio de", "muito", "pouco"], "ans": 0, "exp": "sem."}, {"q": "Sufixo típico de substantivo:", "ctx": "", "opts": ["-tion / -ment", "-ly", "-ish", "-est"], "ans": 0, "exp": "-tion/-ment."}, {"q": "'inform' + ation =", "ctx": "", "opts": ["information", "informment", "informness", "informly"], "ans": 0, "exp": "information."}]$j$::jsonb),

